def validate_cart_items(cart_items, inventory):
    for item in cart_items:
        if item['id'] not in inventory or inventory[item['id']]['stock'] < item['quantity']:
            raise ValueError("Invalid cart item or insufficient stock")
    return True

def apply_discount_codes(cart_total, discount_code, user_role, valid_codes):
    if discount_code in valid_codes:
        code_details = valid_codes[discount_code]
        if (code_details['role'] == 'admin' and user_role != 'admin') or (user_role not in code_details['allowed_roles']):
            raise PermissionError("User not authorized for this discount code")
        return cart_total * (1 - code_details['discount'])
    return cart_total

def calculate_tax(cart_total, tax_rate):
    return cart_total * tax_rate

def process_payment(cart_total, payment_info):
    # Simulate payment processing
    if not payment_info.get('valid', False):
        raise ValueError("Payment processing failed")
    return True

def create_order_record(user_id, cart_items, final_amount):
    order_id = f"ORD-{user_id}-{int(time.time())}"
    order_record = {
        'order_id': order_id,
        'user_id': user_id,
        'items': cart_items,
        'total_amount': final_amount,
        'status': 'completed'
    }
    return order_record

def checkout_process(user_id, cart_items, discount_code, payment_info, user_role, inventory, valid_codes, tax_rate):
    try:
        # Step 1: Validate cart items
        validate_cart_items(cart_items, inventory)
        
        # Step 2: Apply discount codes
        cart_total = sum(item['price'] * item['quantity'] for item in cart_items)
        cart_total = apply_discount_codes(cart_total, discount_code, user_role, valid_codes)
        
        # Step 3: Calculate tax
        tax = calculate_tax(cart_total, tax_rate)
        final_amount = cart_total + tax
        
        # Step 4: Process payment
        process_payment(final_amount, payment_info)
        
        # Step 5: Create order record
        order_record = create_order_record(user_id, cart_items, final_amount)
        
        return order_record
    except Exception as e:
        return {'error': str(e)}

